// Extract item_ids from the incoming normalized items array.
// Also build the SQL IN clause for the targeted D1 lookup.
const input = $input.first().json;
const items = Array.isArray(input.items) ? input.items : [];
const ids = items.map(i => i.item_id).filter(Boolean);
// Build parameterized placeholders for the IN clause
const placeholders = ids.map(() => '?').join(', ');
const sql = ids.length > 0
  ? `SELECT json_extract(metadata_json, '$.item_id') AS item_id FROM alerts WHERE date_key >= date('now', '-1 day') AND json_extract(metadata_json, '$.item_id') IN (${placeholders})`
  : "SELECT NULL AS item_id WHERE 0";
return [{ json: { items, ids, d1_sql: sql, d1_params: ids } }];

// Build a set of known item_ids from D1 response.
// Compare against incoming items and mark duplicates.
// Also deduplicate within the current batch by item_id.
const d1Response = $input.first().json;
const results = d1Response?.result?.[0]?.results || [];
const knownIds = new Set(results.map(r => r.item_id).filter(Boolean));

const allItems = $('Extract Item IDs').first().json.items || [];

// Deduplicate within the current batch first (keep first occurrence)
const seenInBatch = new Set();
const uniqueItems = allItems.filter(item => {
  if (!item.item_id || seenInBatch.has(item.item_id)) return false;
  seenInBatch.add(item.item_id);
  return true;
});

// Then filter out IDs already in D1
const newItems = uniqueItems.filter(item => !knownIds.has(item.item_id));

return [{
  json: {
    items: newItems,
    total_input: allItems.length,
    batch_duplicates_dropped: allItems.length - uniqueItems.length,
    d1_duplicates_dropped: uniqueItems.length - newItems.length
  }
}];
